import React, { useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { authService } from '../services/authService';

const COLORS = {
  bg: '#0a0f1e',
  bgAlt: '#1A2B4C',
  accent: '#007BFF',
  text: '#ffffff',
  textMuted: '#8b9ab4',
  border: 'rgba(255,255,255,0.08)',
  cardBg: 'rgba(255,255,255,0.05)',
  cardBorder: 'rgba(255,255,255,0.1)',
};

const steps = [
  {
    num: '01',
    title: 'Importa tu Excel',
    desc: 'Exporta los pagos desde tu ERP y subelos a VitaSoft con un solo clic.',
  },
  {
    num: '02',
    title: 'Valida y corregi',
    desc: 'El sistema detecta errores y te permite completar datos faltantes como el CBU.',
  },
  {
    num: '03',
    title: 'Genera y descarga',
    desc: 'Obtene el archivo TXT listo para subir al home banking de tu banco.',
  },
];

function useFadeIn() {
  const refs = useRef([]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.style.opacity = '1';
            entry.target.style.transform = 'translateY(0)';
          }
        });
      },
      { threshold: 0.15 }
    );
    refs.current.forEach((el) => el && observer.observe(el));
    return () => observer.disconnect();
  }, []);

  const addRef = (el) => {
    if (el && !refs.current.includes(el)) refs.current.push(el);
  };

  return addRef;
}

export default function Landing() {
  const navigate = useNavigate();
  const addFadeRef = useFadeIn();

  useEffect(() => {
    if (authService.isAuthenticated()) {
      navigate('/dashboard', { replace: true });
    }
  }, [navigate]);

  const goLogin = () => navigate('/login');

  const scrollToHow = () => {
    const el = document.getElementById('como-funciona');
    if (el) el.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div style={{ background: COLORS.bg, color: COLORS.text, minHeight: '100vh', fontFamily: 'inherit' }}>
      {/* ===== NAVBAR ===== */}
      <nav style={css.navbar}>
        <div style={css.navInner}>
          <span style={css.logo}>VitaSoft</span>
          <div style={css.navButtons}>
            <button className="landing-btn landing-btn-outline" style={css.btnOutline} onClick={goLogin}>Iniciar sesion</button>
            <button className="landing-btn" style={css.btnFilled} onClick={goLogin}>Comenzar</button>
          </div>
        </div>
      </nav>

      {/* ===== HERO ===== */}
      <section style={css.hero}>
        <div ref={addFadeRef} style={css.fadeTarget}>
          <h1 style={css.heroTitle}>
            Automatiza tus{' '}
            <span style={{ color: COLORS.accent }}>pagos</span>
            <br />a proveedores.
            <br />Sin errores. Sin demoras.
          </h1>
          <p style={css.heroSub}>
            VitaSoft convierte tu Excel en archivos TXT compatibles con
            Credicoop, Galicia y Santander en segundos.
          </p>
          <div style={css.heroBtns}>
            <button className="landing-btn" style={css.btnFilledLg} onClick={goLogin}>Comenzar ahora</button>
            <button className="landing-btn landing-btn-outline" style={css.btnOutlineLg} onClick={scrollToHow}>Ver como funciona</button>
          </div>
        </div>
      </section>

      {/* ===== COMO FUNCIONA ===== */}
      <section id="como-funciona" style={css.howSection}>
        <h2 ref={addFadeRef} style={{ ...css.sectionTitle, ...css.fadeTarget }}>
          De Excel a tu banco en 3 pasos
        </h2>
        <div style={css.stepsGrid}>
          {steps.map((s) => (
            <div key={s.num} ref={addFadeRef} className="landing-card" style={{ ...css.card, ...css.fadeTarget }}>
              <div style={css.stepNum}>{s.num}</div>
              <h3 style={css.cardTitle}>{s.title}</h3>
              <p style={css.cardDesc}>{s.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* ===== CTA ===== */}
      <section ref={addFadeRef} style={{ ...css.ctaSection, ...css.fadeTarget }}>
        <h2 style={css.ctaTitle}>Empeza a ahorrar tiempo hoy.</h2>
        <p style={css.ctaSub}>
          Mas de 100 empresas ya usan VitaSoft para automatizar sus pagos masivos.
        </p>
        <button className="landing-btn" style={css.btnFilledLg} onClick={goLogin}>Crear cuenta gratis</button>
      </section>

      {/* ===== FOOTER ===== */}
      <footer style={css.footer}>
        <span style={{ fontWeight: 700, fontSize: 16 }}>VitaSoft</span>
        <span style={{ color: COLORS.textMuted, fontSize: 13 }}>
          &copy; 2026 VitaSoft. Todos los derechos reservados.
        </span>
      </footer>
    </div>
  );
}

/* ===== STYLES ===== */

const css = {
  /* Navbar */
  navbar: {
    position: 'sticky',
    top: 0,
    zIndex: 100,
    backdropFilter: 'blur(12px)',
    WebkitBackdropFilter: 'blur(12px)',
    background: 'rgba(10,15,30,0.75)',
    borderBottom: `1px solid ${COLORS.border}`,
  },
  navInner: {
    maxWidth: 1100,
    margin: '0 auto',
    padding: '16px 24px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  logo: {
    fontSize: 22,
    fontWeight: 700,
    letterSpacing: 1,
    color: COLORS.text,
  },
  navButtons: {
    display: 'flex',
    gap: 10,
  },

  /* Buttons */
  btnOutline: {
    background: 'transparent',
    color: COLORS.text,
    border: `1px solid ${COLORS.cardBorder}`,
    borderRadius: 6,
    padding: '8px 20px',
    fontSize: 14,
    cursor: 'pointer',
    transition: 'all 0.2s',
  },
  btnFilled: {
    background: COLORS.accent,
    color: '#fff',
    border: 'none',
    borderRadius: 6,
    padding: '8px 20px',
    fontSize: 14,
    cursor: 'pointer',
    transition: 'all 0.2s',
  },
  btnOutlineLg: {
    background: 'transparent',
    color: COLORS.text,
    border: `1px solid ${COLORS.cardBorder}`,
    borderRadius: 8,
    padding: '14px 32px',
    fontSize: 16,
    cursor: 'pointer',
    transition: 'all 0.2s',
  },
  btnFilledLg: {
    background: COLORS.accent,
    color: '#fff',
    border: 'none',
    borderRadius: 8,
    padding: '14px 32px',
    fontSize: 16,
    fontWeight: 600,
    cursor: 'pointer',
    transition: 'all 0.2s',
  },

  /* Hero */
  hero: {
    minHeight: '90vh',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    textAlign: 'center',
    padding: '80px 24px 60px',
    background: `linear-gradient(180deg, ${COLORS.bg} 0%, ${COLORS.bgAlt} 100%)`,
  },
  heroTitle: {
    fontSize: 'clamp(32px, 5vw, 56px)',
    fontWeight: 800,
    lineHeight: 1.15,
    marginBottom: 24,
  },
  heroSub: {
    fontSize: 18,
    color: COLORS.textMuted,
    maxWidth: 540,
    margin: '0 auto 36px',
    lineHeight: 1.6,
  },
  heroBtns: {
    display: 'flex',
    gap: 14,
    justifyContent: 'center',
    flexWrap: 'wrap',
  },

  /* How it works */
  howSection: {
    maxWidth: 1100,
    margin: '0 auto',
    padding: '100px 24px',
  },
  sectionTitle: {
    fontSize: 'clamp(24px, 3.5vw, 36px)',
    fontWeight: 700,
    textAlign: 'center',
    marginBottom: 56,
  },
  stepsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
    gap: 24,
  },
  card: {
    background: COLORS.cardBg,
    border: `1px solid ${COLORS.cardBorder}`,
    borderRadius: 12,
    padding: 32,
    transition: 'transform 0.25s ease, box-shadow 0.25s ease',
    cursor: 'default',
  },
  stepNum: {
    fontSize: 40,
    fontWeight: 800,
    color: COLORS.accent,
    opacity: 0.35,
    marginBottom: 12,
  },
  cardTitle: {
    fontSize: 18,
    fontWeight: 600,
    marginBottom: 10,
  },
  cardDesc: {
    fontSize: 14,
    color: COLORS.textMuted,
    lineHeight: 1.6,
  },

  /* CTA */
  ctaSection: {
    background: COLORS.bgAlt,
    textAlign: 'center',
    padding: '80px 24px',
  },
  ctaTitle: {
    fontSize: 'clamp(24px, 3.5vw, 36px)',
    fontWeight: 700,
    marginBottom: 16,
  },
  ctaSub: {
    fontSize: 16,
    color: COLORS.textMuted,
    marginBottom: 32,
    maxWidth: 480,
    margin: '0 auto 32px',
    lineHeight: 1.5,
  },

  /* Footer */
  footer: {
    background: COLORS.bg,
    borderTop: `1px solid ${COLORS.border}`,
    padding: '24px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    flexWrap: 'wrap',
    gap: 12,
    maxWidth: 1100,
    margin: '0 auto',
  },

  /* Fade-in target (initial state) */
  fadeTarget: {
    opacity: 0,
    transform: 'translateY(24px)',
    transition: 'opacity 0.7s ease, transform 0.7s ease',
  },
};
